        const firstIndex = Math.max(firstVisibleIndex - bufferSize, 0);
        let lastIndex = firstVisibleIndex - bufferSize + renderedRowCount;
        const firstVisibleKey = rows[firstVisibleIndex] && rows[firstVisibleIndex].key;
